12697     Builder.SetInsertPoint(ReductionRoot->getParent(),
12698                            ReductionRoot->getIterator());
12699   else
12700     Builder.SetInsertPoint(&F->getEntryBlock(), F->getEntryBlock().begin());
12701 
12702   // Postpone emission of PHIs operands to avoid cyclic dependencies issues.
12703   (void)vectorizeTree(VectorizableTree[0].get(), /*PostponedPHIs=*/true);
12704   for (const std::unique_ptr<TreeEntry> &TE : VectorizableTree)
12705     if (TE->State == TreeEntry::Vectorize &&
12706         TE->getOpcode() == Instruction::PHI && !TE->isAltShuffle() &&
12707         TE->VectorizedValue)
12708       (void)vectorizeTree(TE.get(), /*PostponedPHIs=*/false);
12709   // Run through the list of postponed gathers and emit them, replacing the temp
12710   // emitted allocas with actual vector instructions.
12711   ArrayRef<const TreeEntry *> PostponedNodes = PostponedGathers.getArrayRef();
12712   DenseMap<Value *, SmallVector<TreeEntry *>> PostponedValues;
12713   for (const TreeEntry *E : PostponedNodes) {
12714     auto *TE = const_cast<TreeEntry *>(E);
