12741           continue;
12742         if (UI->comesBefore(InsertPt))
12743           InsertPt = UI;
12744       }
12745       Builder.SetInsertPoint(InsertPt);
12746     } else {
12747       Builder.SetInsertPoint(PrevVec);
12748     }
12749     Builder.SetCurrentDebugLocation(UserI->getDebugLoc());
